            }
        }

        // Check IPv6 loopback and unique local addresses (fc00::/7)
        if (ip.startsWith("0:0:0:0:0:0:0:1") || ip.startsWith("::1") || 
            ip.startsWith("fc") || ip.startsWith("fd")) {
            return true;
        }

        return false;
    }
